183	/// Array with size.
184	///
185	/// # Memory layout
186	///
187	/// An array consisting of size and elements:
188	///
189	/// ```text
190	///          elements
191	///          |
192	///          |
193	/// ------------------------------------
194	/// | size | 0 | 1 | 2 | 3 | 4 | 5 | 6 |
195	/// ------------------------------------
196	/// ```
197	///
198	/// Its memory layout is different from that of `Box<[T]>` in that size is in the allocation (not
199	/// along with pointer as in `Box<[T]>`).
200	///
201	/// Elements are not present in the type, but they will be in the allocation.
202	#[repr(C)]
203	struct Array<T> {
204	    /// The number of elements (not the number of bytes).
205	    len: usize,
206	    elements: [MaybeUninit<T>; 0],
207	}
