572	    /// Fetches the pointer, and then applies a function to it that returns a new value.
573	    /// Returns a `Result` of `Ok(previous_value)` if the function returned `Some`, else `Err(_)`.
574	    ///
575	    /// Note that the given function may be called multiple times if the value has been changed by
576	    /// other threads in the meantime, as long as the function returns `Some(_)`, but the function
577	    /// will have been applied only once to the stored value.
578	    ///
579	    /// `fetch_update` takes two [`Ordering`] arguments to describe the memory
580	    /// ordering of this operation. The first describes the required ordering for
581	    /// when the operation finally succeeds while the second describes the
582	    /// required ordering for loads. These correspond to the success and failure
583	    /// orderings of [`Atomic::compare_exchange`] respectively.
584	    ///
585	    /// Using [`Acquire`] as success ordering makes the store part of this
586	    /// operation [`Relaxed`], and using [`Release`] makes the final successful
587	    /// load [`Relaxed`]. The (failed) load ordering can only be [`SeqCst`],
588	    /// [`Acquire`] or [`Relaxed`] and must be equivalent to or weaker than the
589	    /// success ordering.
590	    ///
591	    /// [`Relaxed`]: Ordering::Relaxed
592	    /// [`Acquire`]: Ordering::Acquire
593	    /// [`Release`]: Ordering::Release
594	    /// [`SeqCst`]: Ordering::SeqCst
595	    ///
596	    /// # Examples
597	    ///
598	    /// ```
599	    /// use crossbeam_epoch::{self as epoch, Atomic};
600	    /// use std::sync::atomic::Ordering::SeqCst;
601	    ///
602	    /// let a = Atomic::new(1234);
603	    /// let guard = &epoch::pin();
604	    ///
605	    /// let res1 = a.fetch_update(SeqCst, SeqCst, guard, |x| Some(x.with_tag(1)));
606	    /// assert!(res1.is_ok());
607	    ///
608	    /// let res2 = a.fetch_update(SeqCst, SeqCst, guard, |x| None);
609	    /// assert!(res2.is_err());
610	    /// # unsafe { drop(a.into_owned()); } // avoid leak
611	    /// ```
612	    pub fn fetch_update<'g, F>(
613	        &self,
614	        set_order: Ordering,
615	        fail_order: Ordering,
616	        guard: &'g Guard,
617	        mut func: F,
618	    ) -> Result<Shared<'g, T>, Shared<'g, T>>
619	    where
620	        F: FnMut(Shared<'g, T>) -> Option<Shared<'g, T>>,
621	    {
622	        let mut prev = self.load(fail_order, guard);
623	        while let Some(next) = func(prev) {
624	            match self.compare_exchange_weak(prev, next, set_order, fail_order, guard) {
625	                Ok(result) => return Ok(result.old),
626	                Err(next_prev) => prev = next_prev.current,
627	            }
628	        }
629	        Err(prev)
630	    }
